async function loadLiveCollaborators(grid){
  const project=window.reliableProject?.topic||window.reliableProject?.idea||'student research';
  try{
    const response=await fetch(`https://api.openalex.org/authors?search=${encodeURIComponent(project)}&per-page=75`);
    const data=await response.json();
    const matches=(data.results||[]).filter(author=>author.display_name&&author.last_known_institutions?.[0]?.display_name).slice(0,75).map((author,index)=>[
      author.display_name,author.last_known_institutions[0].display_name,'Public researcher profile · matched to '+project,`${Math.max(50,96-Math.floor(index*.55))}% fit`,initials(author.display_name)
    ]);
    if(matches.length>=12){grid.innerHTML=matches.map(collaboratorCard).join('');showToast(`${matches.length} public researcher profiles loaded`,'Profiles are sourced live from OpenAlex and can be searched, sorted, or saved.');}
  }catch{showToast('Live researcher search unavailable','Showing curated starter matches.');}
}
