function gradeAbstractEnhanced(text){
  const words=text.trim().split(/\s+/).filter(Boolean);if(words.length<40)return showToast('Add more detail','Use at least 40 words so the rubric can identify a complete research story.');
  const lower=` ${text.toLowerCase()} `;const sentences=text.split(/[.!?]+/).map(s=>s.trim()).filter(Boolean);const has=(pattern)=>pattern.test(lower);const range=(value,min,max)=>value>=min&&value<=max?20:value>=min-40&&value<=max+60?14:value>=80&&value<=420?8:3;
  const length=range(words.length,150,300);
  const question=(has(/\b(problem|challenge|gap|unknown|unclear|little is known|aim|objective|hypothesis)\b/)?10:3)+(has(/\b(cancer|patient|cell|population|system|disease|outcome|response)\b/)?5:2)+(has(/\b(because|however|although|despite)\b/)?5:2);
  const methods=(has(/\b(we (analyzed|measured|tested|examined|conducted|used)|participants|samples|dataset|experiment|trial|assay|sequenc|regression|survey)\b/)?12:3)+(has(/\b(n\s*=|\d+ (samples|participants|patients|mice|cells|studies))\b/)?5:1)+(has(/\b(control|comparison|baseline|random|adjusted)\b/)?3:1);
  const results=(has(/\b(found|observed|resulted|showed|demonstrated|associated|increased|decreased|predicted)\b/)?10:2)+(has(/\b(\d+%|p\s*[<=>]|confidence interval|odds ratio|fold|median|mean|\d+\.?\d*)\b/)?7:1)+(has(/\b(significant|difference|association|correlation|response)\b/)?3:1);
  const conclusion=(has(/\b(suggest|indicate|implic|support|may|could|potential)\b/)?8:2)+(has(/\b(limit|future|validate|further|prospective|caution)\b/)?6:2)+(sentences.length>=3&&sentences.length<=8?6:3);
  const checks=[['Length & concision',length],['Research question',question],['Methods specificity',methods],['Results evidence',results],['Conclusion discipline',conclusion]].map(([name,value])=>[name,Math.min(20,Math.round(value))]);
  const score=checks.reduce((sum,item)=>sum+item[1],0);const missing=checks.filter(x=>x[1]<12).map(x=>x[0].toLowerCase());
  workspace.querySelector('#abstractScore').textContent=score;workspace.querySelector('#scoreLabel').textContent=score>=85?'Judge-ready abstract':score>=70?'Strong foundation—sharpen the weak links':score>=50?'Promising, but incomplete':'Needs a clearer research story';workspace.querySelector('#scoreSummary').textContent=missing.length?`Prioritize: ${missing.join(', ')}. Scores are based on explicit signals in your text, not a random model guess.`:'Every core component is present. Now verify that each claim is supported by a specific result.';workspace.querySelector('#scoreBreakdown').innerHTML=checks.map(x=>`<div class="grade-row"><span>${x[0]}</span><b>${x[1]}/20</b><i style="width:${x[1]*5}%"></i></div>`).join('');showToast('Abstract graded',`${score}/100 from a transparent five-part rubric.`);
}
function gradeAbstract(text){gradeAbstractEnhanced(text);}
function gradeScienceFairAbstract(text){
  const words=text.trim().split(/\s+/).filter(Boolean);if(words.length<35)return showToast('Abstract is too short','Add at least 35 words before requesting a science-fair evaluation.');
  const lower=` ${text.toLowerCase()} `;const has=(regex)=>regex.test(lower);const count=(regex)=>(lower.match(regex)||[]).length;const sentences=text.split(/[.!?]+/).map(s=>s.trim()).filter(Boolean);const evidence=[];const strengths=[],weaknesses=[],missing=[],improvements=[],deductions=[];
  const concise=words.length>=150&&words.length<=300?3:words.length>=100&&words.length<=350?2:1;
  const context=(has(/\b(problem|challenge|gap|unknown|limited|unmet|despite|however)\b/)?4:0)+(has(/\b(health|disease|patient|environment|energy|education|society|cost|risk|outcome|impact)\b/)?3:0)+concise;
  const objective=(has(/\b(aim|objective|purpose|hypothesis|research question|we investigated|we tested|we examined)\b/)?10:0)+(has(/\b(effect|association|predict|compare|whether|relationship|difference)\b/)?5:0);
  const methodSignals=[/\b(n\s*=|\d+ (samples|participants|patients|mice|cells|images|records|trials|studies))\b/,/\b(dataset|cohort|biobank|nhanes|tcga|se[er]+|uk biobank|mimic)\b/,/\b(control|placebo|baseline|comparison group|randomi[sz]|blinded)\b/,/\b(assay|microscope|pcr|sequenc|immunohistochemistry|survey|instrument|protocol)\b/,/\b(python|r\b|matlab|spss|tensorflow|pytorch|algorithm|model)\b/,/\b(cross.validation|train.test|validation set|bootstrap|replicat)\b/,/\b(regression|t.test|anova|chi.square|mann.whitney|statistical test)\b/];
  const methodHits=methodSignals.filter(has).length;const methods=Math.min(30,methodHits*4+(has(/\b(independent variable|dependent variable|outcome|exposure)\b/)?2:0));
  const resultSignals=[/\b\d+(?:\.\d+)?%\b/,/\bp\s*[<=>]\s*0?\.\d+\b/,/\b(confidence interval|auc|f1|precision|recall|accuracy|sensitivity|specificity|effect size|odds ratio|hazard ratio|fold change)\b/,/\b(mean|median|standard deviation|ci\b)\b/,/\b(compared with|versus|outperformed|higher than|lower than)\b/];
  const resultHits=resultSignals.filter(has).length;const results=Math.min(30,resultHits*5+(has(/\b(found|observed|showed|demonstrated|associated)\b/)?3:0)+(has(/\b(significant|non.significant)\b/)?2:0));
  const conclusion=(has(/\b(suggest|indicate|support|may|could|potential)\b/)?4:0)+(has(/\b(limit|limitation|future work|further research|validate|replicate|prospective)\b/)?4:0)+(has(/\b(revolutionize|prove|cure|guarantee|all patients|always)\b/)?0:2);
  const clarity=Math.min(5,(sentences.length>=3&&sentences.length<=9?2:1)+(words.length/sentences.length<=32?2:1)+(!has(/\b(really|lots of|many|some|several|around|kind of|very effective|worked well|successful)\b/)?1:0));
  const rubric=[['Background',Math.min(10,context),10],['Objective',Math.min(15,objective),15],['Methodology',methods,30],['Results',results,30],['Conclusion',Math.min(10,conclusion),10],['Clarity',clarity,5]];
  if(context>=7)strengths.push('Provides a concise, relevant scientific context.');else{weaknesses.push('The motivation is vague or does not establish why the problem matters.');missing.push('A concise scientific context and significance statement.');improvements.push('Open with one sentence defining the specific problem and why it matters.');}
  if(objective>=10)strengths.push('States a recognizable research objective or hypothesis.');else{weaknesses.push('The research objective or hypothesis is not explicit enough.');missing.push('A specific objective, hypothesis, or testable research question.');improvements.push('State exactly what relationship, effect, or comparison you tested.');}
  if(methods>=18)strengths.push(`Methods include ${methodHits} concrete design or analysis details.`);else{weaknesses.push('Methodology is not reproducible from the abstract.');missing.push('Sample/dataset description, design, controls, procedures, and analysis details.');improvements.push('Name the sample or dataset, n, comparison/control, tools, and validation or statistical approach.');}
  if(results>=18)strengths.push(`Results include ${resultHits} explicit quantitative evidence signal${resultHits===1?'':'s'}.`);else{weaknesses.push('Results are qualitative, incomplete, or lack a defensible numerical comparison.');missing.push('Exact numerical findings, evaluation metrics, statistical significance, or baseline comparison.');improvements.push('Replace claims such as “performed well” with a metric, effect size, p-value, CI, or direct baseline comparison.');}
  if(conclusion>=7)strengths.push('Conclusion uses appropriately cautious language and acknowledges limits or next steps.');else{weaknesses.push('Conclusion is unsupported, overly broad, or lacks limitations.');missing.push('A limitation and a conclusion limited to the presented evidence.');improvements.push('Add one limitation or validation need, and avoid claims beyond the measured system.');}
  const vagueWords=['really','lots of','many','some','several','around','kind of','very effective','worked well','successful'];const vagueCount=vagueWords.reduce((n,w)=>n+(lower.includes(` ${w} `)?1:0),0);let deduction=0;if(vagueCount){deduction+=Math.min(8,vagueCount*2);deductions.push(`${vagueCount} vague term${vagueCount===1?'':'s'} detected (−${Math.min(8,vagueCount*2)}).`);}if(methods<10){deduction+=6;deductions.push('Methodology is largely missing (−6).');}if(results<10){deduction+=7;deductions.push('Quantitative results are largely missing (−7).');}if(!has(/\b(dataset|sample|participant|patient|cohort|n\s*=|\d+ (samples|participants|patients|mice|cells|images|records))\b/)){deduction+=4;deductions.push('No dataset or sample description (−4).');}if(!has(/\b(accuracy|auc|f1|precision|recall|p\s*[<=>]|confidence interval|effect size|odds ratio|mean|median|%|significant)\b/)){deduction+=4;deductions.push('No evaluation metric or quantitative result (−4).');}if(!has(/\b(limit|limitation|future work|validate|further research|replicate)\b/)){deduction+=2;deductions.push('No limitations or grounded future work (−2).');}
  let score=Math.max(0,rubric.reduce((sum,x)=>sum+x[1],0)-deduction);if(methods<10||results<10)score=Math.min(score,60);if(objective<6&&results<10)score=Math.min(score,55);score=Math.round(score);
  const label=score>=90?'Exceptional scientific abstract':score>=80?'Strong science-fair abstract':score>=65?'Average abstract with important gaps':'Weak abstract—scientific detail is missing';const summary=score>=80?'This abstract earns a strong score because it explicitly reports the problem, test, and evidence. Its remaining score depends on whether the reported methods and findings are complete enough to evaluate rigor.':score>=65?'The abstract has the beginning of a research story, but the score is limited by scientific details that are absent or not explicit. Adding polished language alone would not raise this score.':'The abstract does not yet provide enough explicit methodology or quantitative evidence to support its claims. A judge cannot infer rigor that is not stated.';
  workspace.querySelector('#abstractScore').textContent=score;workspace.querySelector('#scoreLabel').textContent=label;workspace.querySelector('#scoreSummary').textContent=summary;workspace.querySelector('#scoreBreakdown').innerHTML=`<div class="judge-report"><h3>Rubric Breakdown</h3>${rubric.map(x=>`<div class="grade-row"><span>${x[0]}</span><b>${x[1]}/${x[2]}</b><i style="width:${x[1]/x[2]*100}%"></i></div>`).join('')}<h3>Strengths</h3><ul>${(strengths.length?strengths:['No major scientific strengths can be verified from the text alone.']).map(x=>`<li>${x}</li>`).join('')}</ul><h3>Weaknesses</h3><ul>${weaknesses.map(x=>`<li>${x}</li>`).join('')}</ul><h3>Missing Information</h3><ul>${missing.map(x=>`<li>${x}</li>`).join('')}</ul><h3>Specific Improvements</h3><ul>${improvements.map(x=>`<li>${x}</li>`).join('')}</ul>${deductions.length?`<h3>Automatic Deductions</h3><ul>${deductions.map(x=>`<li>${x}</li>`).join('')}</ul>`:''}<h3>Judge’s Summary</h3><p>${summary}</p></div>`;showToast('Science fair evaluation complete',`${score}/100 — strict rubric with explicit deductions.`);
}
